137|// Canonical = sorted file paths (relative to ProjectDir, forward slashes) +
138|// each file's content. Respects .agentpaasignore exclusions.
139|// Symlink-safe: uses os.Lstat, rejects symlinks.
140|func ComputeBuildInputDigest(projectDir string, ignore *IgnoreMatcher) (string, error) {
141|	files, err := collectBuildFiles(projectDir, ignore)
