148|		if _, err := io.WriteString(h, file.relPath); err != nil {
149|			return "", fmt.Errorf("hash path %s: %w", file.relPath, err)
150|		}
151|		if _, err := h.Write([]byte{0}); err != nil {
152|			return "", fmt.Errorf("hash separator: %w", err)
153|		}
154|		if _, err := io.WriteString(h, fmt.Sprint(file.info.Size())); err != nil {
155|			return "", fmt.Errorf("hash size %s: %w", file.relPath, err)
156|		}
